void setup() {
#ifdef ARDUINO_M5STACK_STICKC    
  pinMode(10, OUTPUT);
  digitalWrite(10, LOW);
#endif

#ifdef ARDUINO_M5STACK_STICKCPLUS
  M5.begin();
#else
  m5::M5Unified::config_t cfg;
  memset(&cfg, 0, sizeof(cfg));
#ifdef ARDUINO_M5Stack_ATOMS3
  cfg.external_display.atom_display = true;
#endif
  M5.begin(cfg);
#endif

#ifdef ARDUINO_M5STACK_STICKCPLUS
  M5.Axp.SetPeripherialsPower(true);
#endif

#ifndef ARDUINO_M5STACK_STICKCPLUS
  M5.Lcd.beginTransaction();
#endif
  M5.Lcd.fillScreen(TFT_BLACK);
  drawImage();
  M5.Lcd.fillRect(M5.Lcd.width()-16, 16, 16, 16, MYORANGE);
  M5.Lcd.setTextSize(2);
  M5.Lcd.setTextColor(TFT_WHITE);
  const char* title = "C128BLE";
#ifdef ARDUINO_M5STACK_STICKC
#ifndef ARDUINO_M5STACK_STICKCPLUS
  M5.Lcd.setTextSize(1.5);
  ++title;
#endif
#endif
  auto w = M5.Lcd.textWidth(title);
  auto x = (M5.Lcd.width() - w - 16) / 2;
  auto y = 16;
  M5.Lcd.setCursor(x, y);
  M5.Lcd.print(title);
#ifndef ARDUINO_M5STACK_STICKCPLUS
  M5.Lcd.endTransaction();
#endif
  Serial.begin(115200);
  Serial.setTimeout(0); // so we don't wait for reads
#ifdef ARDUINO_M5Stack_ATOMS3
  Wire.begin(G2, G1, 100000UL); // ATOMS3
#endif
#ifdef ARDUINO_M5Stick_C
  Wire.begin(32, 33, 100000UL); // M5Stick-C and Plus and related
#endif
#ifdef ARDUINO_M5STACK_CORE
  Wire.begin(SDA, SCL, 100000UL);
#endif  
  for (int i=1; !CardKB && i<=5; ++i)
  {
    if (Wire.requestFrom((uint8_t)0x5F, (size_t)1, true) == 1)
    {
      CardKB = true;
      break;
    }
    delay(100);
  }
  if (!CardKB)
  {
    Wire.end();
    Serial2.end();
#ifdef ARDUINO_M5Stick_C    
    Serial2.begin(115200, SERIAL_8N1, 32, 33); // M5Stick-C
#endif
#ifdef ARDUINO_M5Stack_ATOMS3    
    Serial2.begin(115200, SERIAL_8N1, G2, G1); // M5AtomS3
#endif
#ifdef ARDUINO_M5Stack_Core_ESP32
    Serial2.begin(115200, SERIAL_8N1, G21, -1); // M5Core
#endif    
    Serial2.setTimeout(0); // so we don't wait for reads
  }

#ifndef ARDUINO_M5STACK_STICKCPLUS
  M5.Lcd.beginTransaction();
#endif  
  M5.Lcd.setCursor(0, 0);
  M5.Lcd.setTextSize(1);
  M5.Lcd.setTextColor(TFT_YELLOW);
  M5.Lcd.print(CardKB ? "CardKB" : "Serial");
#ifndef ARDUINO_M5STACK_STICKCPLUS
  M5.Lcd.endTransaction();
#endif

  Serial.println("Starting Commodore 64/128 BLE Keyboard Service");
  if (CardKB)
    Serial.println("CardKB or USB Serial");
  else
    Serial.println("HW Serial or USB Serial");

  WiFi.disconnect(true); 
  WiFi.mode(WIFI_OFF);

  BLEDevice::init("C128BLE");
  BLEServer *pServer = BLEDevice::createServer();
  pServer->setCallbacks(new MyServerCallbacks());
  BLEService *pService = pServer->createService(SERVICE_UUID);
  pCharacteristic = pService->createCharacteristic(
                                         CHARACTERISTIC_UUID,
                                         BLECharacteristic::PROPERTY_READ |
                                         BLECharacteristic::PROPERTY_NOTIFY
                                       );

  pCharacteristic->setValue("");
  pService->start();
  BLEAdvertising *pAdvertising = BLEDevice::getAdvertising();
  pAdvertising->addServiceUUID(SERVICE_UUID);
  pAdvertising->setScanResponse(true);
  pAdvertising->setMinPreferred(0x06); // functions that help with iPhone connections issue
  pAdvertising->setMinPreferred(0x12); // functions that help with iPhone connections issue
  BLEDevice::startAdvertising();

  Serial.println("Started Commodore 64/128 BLE Keyboard Service");
}

void serviceLED()
{
  static long then = millis();
  static bool state = false;

  long now = millis();
  if ((now - then) >= 1000) {
    state = !state;
#ifdef ARDUINO_M5Stick_C    
    digitalWrite(10, state ? HIGH : LOW);
#endif
    M5.Lcd.fillRect(M5.Lcd.width()-16, 0, 16, 16, state ? MYBLUE : MYWHITE);
    then = now;
  }
}

void loop() {
  serviceLED();
  String s = "";
  if (CardKB) 
    s = CardKbdScanRead();
  else
    s = Serial2.readString();
  if (s.length() == 0)
    s = Serial.readString();
  if (s.length() == 0)
    return;
  pCharacteristic->setValue(s.c_str());
  pCharacteristic->notify();
}
